import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private static Method isLineBreakCharMethod;
    private static Method isLineBreakCharacterMethod;

    @BeforeAll
    public static void setUp() throws NoSuchMethodException {
        // Access private static method isLineBreak(Character)
        isLineBreakCharacterMethod = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        isLineBreakCharacterMethod.setAccessible(true);
        // Access private static method isLineBreak(char)
        isLineBreakCharMethod = CSVFormat.class.getDeclaredMethod("isLineBreak", char.class);
        isLineBreakCharMethod.setAccessible(true);
    }

    @Test
    public void testIsLineBreak_Character_null() throws IllegalAccessException, InvocationTargetException {
        Boolean result = (Boolean) isLineBreakCharacterMethod.invoke(null, (Character) null);
        assertFalse(result);
    }

    @Test
    public void testIsLineBreak_Character_lineBreakChars() throws IllegalAccessException, InvocationTargetException {
        // Test with '\r' (CR)
        Boolean resultCR = (Boolean) isLineBreakCharacterMethod.invoke(null, Character.valueOf('\r'));
        assertTrue(resultCR);

        // Test with '\n' (LF)
        Boolean resultLF = (Boolean) isLineBreakCharacterMethod.invoke(null, Character.valueOf('\n'));
        assertTrue(resultLF);
    }

    @Test
    public void testIsLineBreak_Character_nonLineBreakChars() throws IllegalAccessException, InvocationTargetException {
        // Test with 'a' - not a line break
        Boolean result = (Boolean) isLineBreakCharacterMethod.invoke(null, Character.valueOf('a'));
        assertFalse(result);

        // Test with space ' '
        Boolean resultSpace = (Boolean) isLineBreakCharacterMethod.invoke(null, Character.valueOf(' '));
        assertFalse(resultSpace);
    }

    @Test
    public void testIsLineBreak_char_lineBreakChars() throws IllegalAccessException, InvocationTargetException {
        // Test with '\r' (CR)
        Boolean resultCR = (Boolean) isLineBreakCharMethod.invoke(null, '\r');
        assertTrue(resultCR);

        // Test with '\n' (LF)
        Boolean resultLF = (Boolean) isLineBreakCharMethod.invoke(null, '\n');
        assertTrue(resultLF);
    }

    @Test
    public void testIsLineBreak_char_nonLineBreakChars() throws IllegalAccessException, InvocationTargetException {
        // Test with 'b' - not a line break
        Boolean result = (Boolean) isLineBreakCharMethod.invoke(null, 'b');
        assertFalse(result);

        // Test with tab '\t'
        Boolean resultTab = (Boolean) isLineBreakCharMethod.invoke(null, '\t');
        assertFalse(resultTab);
    }
}
